    rules = [
      { threshold: 0, increment: 5 },
      { threshold: 100, increment: 10 }
    ];
  }

  const sorted = [...rules].sort((a, b) => b.threshold - a.threshold);
  for (const tier of sorted) {
    if (price >= tier.threshold) {
      return tier.increment;
    }
  }
  return 5; // default fallback
}"

